final:
module RefModule (
    input clk,
    input set_n,
    input d,
    output q);reg q_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge set_n or posedge dbg_halt) begin
    if (~set_n)
        q_reg <= 1'b1;
    else
        q_reg <= d;
end

assign q = q_reg;

endmodule
